      "content": "const express = require('express');
const { sendError } = require('../../lib/errors');
const membersService = require('../service');

const router = express.Router();

router.post('/', (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'User ID and role are required');
  }

  const project = membersService.getProject(req.projectId);
  if (!project) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }

  const member = membersService.addMember(req.projectId, { userId, role });
  if (!member) {
    return sendError(res, 409, 'DUPLICATE_MEMBER', 'User is already a member of the project');
  }

  res.status(201).json({ member });
});

module.exports = router;
