      "content": "const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');

let membersByProject = {};

function getProject(projectId) {
  return projectsService.getProjectById(projectId);
}

function addMember(projectId, memberData) {
  if (!membersByProject[projectId]) {
    membersByProject[projectId] = [];
  }

  const existingMember = membersByProject[projectId].find(member => member.userId === memberData.userId);
  if (existingMember) {
    return null;
  }

  const newMember = { ...memberData, id: randomUUID() };
  membersByProject[projectId].push(newMember);
  return newMember;
}

function getMembers(projectId) {
  return membersByProject[projectId] || [];
}

module.exports = {
  getProject,
  addMember,
  getMembers,
};
